using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: EF 9 removes "Discriminator" from the id by default.
            // Existing docs have id = "Blog|1", so preserve the old format.
            entity.HasDiscriminatorInJsonId();

            // Breaking change #2: EF 9 renames the discriminator property from
            // "Discriminator" to "$type". Existing docs use "Discriminator".
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #3: EF 9 no longer supports HasIndex on Cosmos.
            // Cosmos does not have secondary indexes managed by EF; removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

