}

arguments.new_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }

        // Breaking change #4: EF 9 Cosmos uses patch-based updates by default,
        // sending only changed properties. If sync mode must replace full docs,
        // use ReplaceOperation or accept the new default (patch is usually fine).
        context.SaveChanges();
    }
}

